module RefModule(
    input clk,
    input reset,
    output reg [3:0] gray
    );

    reg [3:0] count;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            count <= 4'b0000;
        end else begin
            count <= count + 1;
        end
    end

    always @(count) begin
        gray = (count >> 1) ^ count;
    end
endmodule
